var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"그 종이에 뭐라 쓰여 있을지는 대충 짐작이 가는군요.","JPN":"その紙に何と書いてあるか、大体見当がつきます。","ENG":"I can guess what is written on that piece of paper.","TWN":"我有稍微猜到那張紙上寫什麼。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"단서는 요란한 인테리어와 상투적인 문구…… 그리고 사장님의 묘하게 들뜬 표정…….","JPN":"手がかりは派手なインテリアとお定まりの文句……それに社長の妙に浮かれた顔……","ENG":"The clues are the overwhelming loud interior, the clichéd phrases… And your strangely excited expression, Boss…","TWN":"線索來自誇張的裝潢和老套的文字……還有老闆臉上有點心虛的表情……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"그렇군요, 사장님께서는 저와 <color=#ffd34c>그걸</color> 맺고 싶은 모양이로군요.","JPN":"なるほど、社長は私と<color=#ffd34c>それ</color>を結びたいのですね。","ENG":"I see. So you want to perform <color=#ffd34c>that</color> with me, Boss?","TWN":"原來如此，老闆是想和我簽<color=#ffd34c>那個</color>嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"하지만 기꺼이 정정해 드리겠습니다.","JPN":"ですが、喜んで訂正いたします。","ENG":"However, I would be more than happy to rephrase.","TWN":"不過我要更正一下。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"저는 이미 성직에 몸담아 주의 적을 심판하는 검이 되기로 맹세했죠.","JPN":"私はすでに聖職に入り、主の敵を審判する剣になると誓いました。","ENG":"I have already sworn my allegiance to the Church and vowed to become the sword of judgment.","TWN":"我已經發誓要奉獻自己在聖職裡，做天主審判仇敵的寶劍。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"그동안 제게 친절을 베푸시고 저를 자주 찾아주셨던 것은 감사하지만, 이렇게 느닷없이 사장님의 <color=#ffd34c>배필</color>이 되라고 하시는 건…….","JPN":"これまで私に親切にしてくださり、よく訪ねてくださったのには感謝いたしますが、こんなに急に社長の<color=#ffd34c>伴侶</color>になれというのは……","ENG":"I appreciate your frequent visits, but if you unexpectedly request that I be your <color=#ffd34c>life companion</color>...","TWN":"謝謝老闆這段時間親切的照顧，還常常來拜訪我，不過突然要成為老闆的<color=#ffd34c>另一半</color>……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"예……? 종이를 뒤집어 보라고요?","JPN":"はい……？　紙をひっくり返せと？","ENG":"Hmm...? You want me to turn the page over?","TWN":"什麼……？把紙翻過來看嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"이, 이건……!?","JPN":"こ、これは……！？","ENG":"Th-this is...?!","TWN":"這…這是……！？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"후, 후후…… 그렇군요. 당했습니다.","JPN":"ふ、ふふ……そうですね。やられました。","ENG":"Ha, ha ha... I see. You got me.","TWN":"呵呵呵……原來如此，我上當了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"다른 사람의 마음을 읽는 데는 꽤 재주가 있다고 생각했는데…….","JPN":"人の心を読むことについては結構才能があると思っていましたが……","ENG":"I always had a talent for reading people, but...","TWN":"我原本以為我很擅長讀人的心思……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"한 수 앞을 읽고 이런 정성스러운 트랩을 준비해두시다니……. 사장님에 비하면, 전 아직 멀었군요.","JPN":"その先まで読み、このような念入りなトラップを用意するとは……社長に比べたら、私はまだまだですね。","ENG":"Thinking one step ahead and devising such an intricate trap... Perhaps I still have a long way to go in comparison to you, Boss.","TWN":"沒想到老闆竟然搶先讀一步，還預備這麼有誠意的惡作劇…… 看來和老闆比起來，我還差得遠呢。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"하지만 전 알고 있답니다. 제 감이 마냥 빗나가기만 하지는 않았다는 것을 말이죠.","JPN":"ですが、私は知っているのです。あながち勘が外れたとはいえないということをです。","ENG":"Nonetheless, there is one thing I am certain of. It is that my intuition does not stray too far.","TWN":"但我知道，我的直覺還是有點準的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"후후, 좋습니다, 계약서를 주시죠.","JPN":"ふふ、いいでしょう。契約書をください。","ENG":"Ha ha, very well. Hand me the contract, if you will.","TWN":"呵呵，好的，把契約給我吧！"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"어떠한 형태로든, 어떠한 관계로든…… 사장님의 힘이 되어 드릴 수 있다면 저 역시 환영입니다.","JPN":"どんな形でも、どんな関係でも……社長の力になれるのなら私も歓迎します。","ENG":"If I can be of any help to you... I welcome it in any form or relationship.","TWN":"無論是以什麼形式，或是什麼樣的名義……我都很樂意成為老闆的助力。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"무엇보다도 책이란 건 읽는 이에게 도움이 되어야 하니까요.","JPN":"何より本というものは、読む者の役に立つべきですから。","ENG":"Above all else, a book is meant to help the reader.","TWN":"畢竟書最重要的就是對讀者有幫助。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};